// sidecar/agents/agent-handler.ts
// AgentHandler interface and registry for multi-agent dispatch.
// Each agent type (claude, codex, etc.) implements AgentHandler and
// registers itself in the registry during sidecar startup.

import { getErrorMessage } from "../../shared/lib/errors";
import type { AgentType, QueryRequest } from "../protocol";

/** Options passed to handleQuery, validated by QueryRequestSchema in protocol.ts */
export type QueryOptions = QueryRequest["options"];

/**
 * Common interface for all agent handlers.
 *
 * Each agent implements these 4 lifecycle methods:
 * - initialize() — one-time setup (e.g., discover executable)
 * - handleQuery() — process a user prompt
 * - handleCancel() — cancel a running session
 * - handleReset() — tear down generator for a session
 */
export interface AgentHandler {
  readonly agentType: AgentType;

  initialize(): { success: boolean; error?: string };

  handleQuery(sessionId: string, prompt: string, options: QueryOptions): Promise<void>;

  handleCancel(sessionId: string): Promise<void>;

  handleReset(sessionId: string): void;
}

// ============================================================================
// Agent Registry
// ============================================================================

const registry = new Map<AgentType, AgentHandler>();

/**
 * Registers an agent handler in the registry.
 * Overwrites any existing handler for the same agentType.
 */
export function registerAgent(handler: AgentHandler): void {
  registry.set(handler.agentType, handler);
}

/**
 * Retrieves the agent handler for a given type.
 * Returns undefined if no handler is registered for that type.
 */
export function getAgent(type: AgentType): AgentHandler | undefined {
  return registry.get(type);
}

/**
 * Initializes all registered agents and returns their results.
 * Called once during sidecar startup after all agents are registered.
 */
export function initializeAllAgents(): Map<AgentType, { success: boolean; error?: string }> {
  const results = new Map<AgentType, { success: boolean; error?: string }>();
  for (const [type, handler] of registry) {
    try {
      const result = handler.initialize();
      results.set(type, result);
    } catch (error) {
      results.set(type, {
        success: false,
        error: getErrorMessage(error),
      });
    }
  }
  return results;
}

/**
 * Clears the registry. Used in tests to reset state between runs.
 */
export function clearAgentRegistry(): void {
  registry.clear();
}

// shared/enums.ts
// Canonical Zod enum schemas — single source of truth for all discriminator
// enums used across frontend, backend, and sidecar.
//
// Import the *Schema when you need runtime validation (Zod .parse/.safeParse).
// Import the inferred *type* when you only need TypeScript checking.
// Both are exported from this file.

import { z } from "zod";

// ── Session ──────────────────────────────────────────────────────────────

/** All possible session statuses across the full lifecycle. */
export const SessionStatusSchema = z.enum([
  "idle",
  "working",
  "error",
  "needs_response",
  "needs_plan_response",
]);
export type SessionStatus = z.infer<typeof SessionStatusSchema>;

export const MessageRoleSchema = z.enum(["user", "assistant"]);
export type MessageRole = z.infer<typeof MessageRoleSchema>;

// ── Workspace ────────────────────────────────────────────────────────────

/** Workspace lifecycle states (git worktree). */
export const WorkspaceStateSchema = z.enum(["ready", "initializing", "archived", "error"]);
export type WorkspaceState = z.infer<typeof WorkspaceStateSchema>;

/** Workspace initialization progress. */
export const SetupStatusSchema = z.enum(["none", "running", "completed", "failed"]);
export type SetupStatus = z.infer<typeof SetupStatusSchema>;

// ── Agent ────────────────────────────────────────────────────────────────

export const AgentTypeSchema = z.enum(["claude", "codex", "unknown"]);
export type AgentType = z.infer<typeof AgentTypeSchema>;

/** Structured error categories for agent error responses. */
export const ErrorCategorySchema = z.enum([
  "auth",
  "rate_limit",
  "context_limit",
  "network",
  "abort",
  "invalid_request",
  "db_write",
  "process_exit",
  "internal",
]);
export type ErrorCategory = z.infer<typeof ErrorCategorySchema>;

// shared/protocol.ts
// Canonical Zod schemas for the JSON-RPC 2.0 request/response protocol
// between the frontend (socketService) and sidecar.
//
// These are RPC contracts (request → response), distinct from the
// notification schemas in session-events.ts (one-way push).

import { z } from "zod";

import { AgentTypeSchema } from "./enums";

// ============================================================================
// RPC Method & Notification Constants
// ============================================================================

/** Methods the frontend can call on the sidecar (request/response) */
export const SIDECAR_METHODS = {
  QUERY: "query",
  CANCEL: "cancel",
  CLAUDE_AUTH: "claudeAuth",
  WORKSPACE_INIT: "workspaceInit",
  CONTEXT_USAGE: "contextUsage",
} as const;

/** Notifications the frontend sends to the sidecar (fire-and-forget) */
export const SIDECAR_NOTIFICATIONS = {
  UPDATE_PERMISSION_MODE: "updatePermissionMode",
  RESET_GENERATOR: "resetGenerator",
} as const;

// ============================================================================
// Shared Field Schemas
// ============================================================================

/** Matches the Claude Agent SDK's PermissionMode union type. */
export const PermissionModeSchema = z.enum([
  "default",
  "acceptEdits",
  "bypassPermissions",
  "plan",
  "dontAsk",
]);
export type PermissionMode = z.infer<typeof PermissionModeSchema>;

// ============================================================================
// Query (frontend → sidecar)
// ============================================================================

/** Options passed alongside a query request. */
export const QueryOptionsSchema = z.object({
  cwd: z.string().min(1),
  model: z.string().min(1).optional(),
  maxThinkingTokens: z.number().int().positive().optional(),
  maxTurns: z.number().int().positive().optional(),
  turnId: z.string().min(1).optional(),
  permissionMode: PermissionModeSchema.optional(),
  claudeEnvVars: z.string().optional(),
  ghToken: z.string().optional(),
  opendevsEnv: z.record(z.string(), z.string()).optional(),
  additionalDirectories: z.array(z.string()).optional(),
  chromeEnabled: z.boolean().optional(),
  strictDataPrivacy: z.boolean().optional(),
  shouldResetGenerator: z.boolean().optional(),
  resume: z.string().min(1).optional(),
  resumeSessionAt: z.string().min(1).optional(),
});
export type QueryOptions = z.infer<typeof QueryOptionsSchema>;

export const QueryRequestSchema = z.object({
  type: z.literal("query"),
  id: z.string().min(1),
  agentType: AgentTypeSchema,
  prompt: z.string().min(1),
  options: QueryOptionsSchema,
});
export type QueryRequest = z.infer<typeof QueryRequestSchema>;

/** Synchronous ACK/reject response for query method. */
export const QueryAckResponseSchema = z.object({
  accepted: z.boolean(),
  reason: z.string().optional(),
});
export type QueryAckResponse = z.infer<typeof QueryAckResponseSchema>;

// ============================================================================
// Cancel (frontend → sidecar)
// ============================================================================

export const CancelRequestSchema = z.object({
  type: z.literal("cancel"),
  id: z.string().min(1),
  agentType: AgentTypeSchema,
});
export type CancelRequest = z.infer<typeof CancelRequestSchema>;

// ============================================================================
// Claude Auth (frontend → sidecar)
// ============================================================================

export const ClaudeAuthRequestSchema = z.object({
  type: z.literal("claude_auth"),
  id: z.string().min(1),
  agentType: AgentTypeSchema,
  options: z.object({
    cwd: z.string().min(1),
  }),
});
export type ClaudeAuthRequest = z.infer<typeof ClaudeAuthRequestSchema>;

// ============================================================================
// Workspace Init (frontend → sidecar)
// ============================================================================

export const WorkspaceInitRequestSchema = z.object({
  type: z.literal("workspace_init"),
  id: z.string().min(1),
  agentType: AgentTypeSchema,
  options: z.object({
    cwd: z.string().min(1),
    ghToken: z.string().optional(),
    claudeEnvVars: z.string().optional(),
  }),
});
export type WorkspaceInitRequest = z.infer<typeof WorkspaceInitRequestSchema>;

// ============================================================================
// Context Usage (frontend → sidecar)
// ============================================================================

export const ContextUsageRequestSchema = z.object({
  type: z.literal("context_usage"),
  id: z.string().min(1),
  agentType: AgentTypeSchema,
  options: z.object({
    cwd: z.string().min(1),
    claudeSessionId: z.string().min(1),
  }),
});
export type ContextUsageRequest = z.infer<typeof ContextUsageRequestSchema>;

// ============================================================================
// Permission / Reset Notifications (frontend → sidecar, fire-and-forget)
// ============================================================================

export const UpdatePermissionModeRequestSchema = z.object({
  type: z.literal("update_permission_mode"),
  id: z.string().min(1),
  agentType: AgentTypeSchema,
  permissionMode: PermissionModeSchema,
});
export type UpdatePermissionModeRequest = z.infer<typeof UpdatePermissionModeRequestSchema>;

export const ResetGeneratorRequestSchema = z.object({
  type: z.literal("reset_generator"),
  id: z.string().min(1),
  agentType: AgentTypeSchema,
});
export type ResetGeneratorRequest = z.infer<typeof ResetGeneratorRequestSchema>;

