  1→// sidecar/agents/claude/claude-handler.ts
  2→// ClaudeAgentHandler — implements AgentHandler for the Claude Agent SDK.
  3→// Orchestrates the generator lifecycle, delegates to focused modules.
  4→
  5→import { query as claudeSDK, type PermissionMode } from "@anthropic-ai/claude-agent-sdk";
  6→import { getErrorMessage } from "../../../shared/lib/errors";
  7→import { createCheckpoint } from "./checkpoint";
  8→import { AsyncQueue } from "../async-queue";
  9→import { createStreamContext } from "./stream-context";
 10→import { classifyError } from "../error-classifier";
 11→import { persistCancellation, notifyAndRecordError } from "../query-lifecycle";
 12→import {
 13→  deserializeMessage,
 14→  processMessage,
 15→  type ProcessMessageOptions,
 16→} from "./message-processor";
 17→import { lookupAgentSessionId } from "../../db/session-writer";
 18→import type { AgentHandler, QueryOptions } from "../agent-handler";
 19→import { buildAgentEnvironment, parseEnvString } from "../env-builder";
 20→import {
 21→  initializeClaude,
 22→  blockIfNotInitialized,
 23→  getClaudeExecutablePath,
 24→} from "./claude-discovery";
 25→import { mapModelForProvider } from "./claude-models";
 26→import { buildSdkOptions, DEFAULT_PROMPT, DEFAULT_SETTING_SOURCES } from "./claude-sdk-options";
 27→import {
 28→  getSession,
 29→  setSession,
 30→  deleteSession,
 31→  getQuery,
 32→  setQuery,
 33→  deleteQuery,
 34→  settingsChanged,
 35→  terminateSession,
 36→  isSessionActive,
 37→  type SessionState,
 38→} from "./claude-session";
 39→
 40→// ============================================================================
 41→// RPC parameter types
 42→// ============================================================================
 43→
 44→interface ClaudeAuthParams {
 45→  id: string;
 46→  cwd: string;
 47→}
 48→
 49→interface WorkspaceInitParams {
 50→  id: string;
 51→  cwd: string;
 52→  ghToken?: string;
 53→  claudeEnvVars?: string;
 54→}
 55→
 56→interface ContextUsageRequest {
 57→  id: string;
 58→  options: { cwd: string; claudeSessionId: string };
 59→}
 60→
 61→interface WorkspaceInitOptions {
 62→  cwd: string;
 63→  ghToken?: string;
 64→  claudeEnvVars?: string;
 65→}
 66→
 67→// ============================================================================
 68→// buildPromptIterable — parses queue messages into SDK-compatible user turns
 69→// ============================================================================
 70→
 71→/**
 72→ * Wraps an AsyncQueue of raw prompt strings into the async-iterable format
 73→ * expected by the Claude Agent SDK. Handles both plain text and JSON-encoded
 74→ * content blocks (when user attaches images).
 75→ */
 76→function buildPromptIterable(queue: AsyncQueue<string>, sessionId: string) {
 77→  return (async function* () {
 78→    for await (const message of queue) {
 79→      let content: string | unknown[] = message;
 80→      if (message && message.startsWith("[")) {
 81→        try {
 82→          const parsed = JSON.parse(message);
 83→          if (Array.isArray(parsed) && parsed.length > 0 && parsed[0]?.type) {
 84→            content = parsed;
 85→          }
 86→        } catch {
 87→          // Not valid JSON — keep as plain text string
 88→        }
 89→      }
 90→
 91→      yield {
 92→        type: "user" as const,
 93→        message: { role: "user" as const, content },
 94→        parent_tool_use_id: null,
 95→        session_id: sessionId,
 96→      };
 97→    }
 98→  })();
 99→}
100→
101→// ============================================================================
102→// ClaudeAgentHandler
103→// ============================================================================
104→
105→export class ClaudeAgentHandler implements AgentHandler {
106→  readonly agentType = "claude" as const;
107→
108→  initialize(): { success: boolean; error?: string } {
109→    return initializeClaude();
110→  }
111→
112→  async handleQuery(sessionId: string, prompt: string, options: QueryOptions): Promise<void> {
113→    const tHandleQuery = Date.now();
114→    console.log(`[TIMING][handleQuery] START session=${sessionId} promptLength=${prompt.length}`);
115→    if (blockIfNotInitialized(sessionId)) return;
116→
117→    const session = getSession(sessionId);
118→    const modelChanged = session?.currentModel !== options.model;
119→    const maxThinkingTokensChanged =
120→      session?.currentMaxThinkingTokens !== options.maxThinkingTokens;
121→    const settingsChangedFlag = settingsChanged(session?.currentSettings, options);
122→
123→    if (session) {
124→      session.turnId = options.turnId;
125→      session.cwd = options.cwd;
126→    }
127→
128→    const canReuse =
129→      isSessionActive(session) && options.shouldResetGenerator !== true && !settingsChangedFlag;
130→
131→    if (canReuse) {
132→      console.log(
133→        `[TIMING][handleQuery] REUSE session=${sessionId} decisionTime=${Date.now() - tHandleQuery}ms`
134→      );
135→
136→      // Hot-swap model if it changed
137→      if (modelChanged && session) {
138→        const query = getQuery(sessionId);
139→        if (query) {
140→          const envVars = options.claudeEnvVars ? parseEnvString(options.claudeEnvVars) : {};
141→          const mappedModel = mapModelForProvider(options.model, envVars);
142→          console.log(
143→            `Model changed from ${session.currentModel} to ${options.model}, using setModel callback`
144→          );
145→          try {
146→            await query.setModel(mappedModel);
147→            const updatedSession = getSession(sessionId);
148→            if (updatedSession) updatedSession.currentModel = options.model;
149→          } catch (error) {
150→            console.error(
151→              `Failed to update model: ${getErrorMessage(error)}`
152→            );
153→          }
154→        }
155→      }
156→
157→      // Hot-swap maxThinkingTokens if it changed
158→      const query = getQuery(sessionId);
159→      if (maxThinkingTokensChanged && session && query) {
160→        try {
161→          await query.setMaxThinkingTokens(options.maxThinkingTokens ?? null);
162→          session.currentMaxThinkingTokens = options.maxThinkingTokens;
163→        } catch (error) {
164→          console.error(
165→            `Failed to update maxThinkingTokens: ${getErrorMessage(error)}`
166→          );
167→        }
168→      }
169→
170→      // Update permission mode if provided
171→      if (query && options.permissionMode) {
172→        try {
173→          await query.setPermissionMode(options.permissionMode as PermissionMode);
174→        } catch (error) {
175→          console.error(
176→            `Failed to update permission mode: ${getErrorMessage(error)}`
177→          );
178→        }
179→      }
180→
181→      // Push the new prompt into the existing generator
182→      // isSessionActive type guard narrows sendMessage to be defined
183→      session.sendMessage(prompt);
184→    } else {
185→      const reason = !session
186→        ? "new session"
187→        : !isSessionActive(session)
188→          ? "no active generator"
189→          : options.shouldResetGenerator
190→            ? "should reset generator"
191→            : "settings changed";
192→      console.log(
193→        `[TIMING][handleQuery] NEW_GENERATOR session=${sessionId} reason="${reason}" decisionTime=${Date.now() - tHandleQuery}ms`
194→      );
195→
196→      if (isSessionActive(session)) {
197→        terminateSession(sessionId);
198→      }
199→
200→      const newSession: SessionState = {
201→        currentSettings: {
202→          claudeEnvVars: options.claudeEnvVars,
203→          additionalDirectories: options.additionalDirectories,
204→          chromeEnabled: options.chromeEnabled,
205→          strictDataPrivacy: options.strictDataPrivacy,
206→        },
207→        currentModel: options.model,
208→        currentMaxThinkingTokens: options.maxThinkingTokens,
209→        turnId: options.turnId,
210→        cwd: options.cwd,
211→      };
212→      setSession(sessionId, newSession);
213→
214→      void this.processWithGenerator(sessionId, prompt, options);
215→    }
216→  }
217→
218→  async handleCancel(sessionId: string): Promise<void> {
219→    console.log("Handling Claude cancel request for session:", sessionId);
220→    if (blockIfNotInitialized(sessionId)) return;
221→
222→    const query = getQuery(sessionId);
223→    const session = getSession(sessionId);
224→
225→    if (isSessionActive(session) && query) {
226→      console.log(`Force-closing query for session ${sessionId}`);
227→
228→      // 1. Flag cancellation so the post-loop path persists the cancelled message
229→      session.cancelledByUser = true;
230→
231→      // 2. Create checkpoint before process dies
232→      if (session.turnId && session.cwd) {
233→        createCheckpoint(sessionId, session.turnId, "end", session.cwd, "claudeHandler");
234→      }
235→
236→      // 3. Force kill: close() terminates CLI subprocess + all children + MCP transports
237→      query.close();
238→
239→      // 4. Signal prompt generator to stop — finally block owns cleanup
240→      terminateSession(sessionId);
241→    } else {
242→      console.log(`No active session found for ${sessionId} to cancel`);
243→    }
244→  }
245→
246→  handleReset(sessionId: string): void {
247→    console.log(`Handling reset generator request for session: ${sessionId}`);
248→    const session = getSession(sessionId);
249→    if (session) {
250→      console.log(`Terminating generator for session ${sessionId} on reset request`);
251→      terminateSession(sessionId);
252→    }
253→  }
254→
255→  // ==========================================================================
256→  // Claude-specific RPC methods (not part of AgentHandler interface)
257→  // ==========================================================================
258→
259→  async claudeAuth(params: ClaudeAuthParams) {
260→    const { accountInfo, error } = await this.getClaudeAccountInfo(params.cwd);
261→    return {
262→      id: params.id,
263→      type: "claude_auth_output",
264→      agentType: "claude",
265→      accountInfo,
266→      error,
267→    };
268→  }
269→
270→  async workspaceInit(params: WorkspaceInitParams) {
271→    const { slashCommands, mcpServers, error } = await this.getClaudeWorkspaceInitData({
272→      cwd: params.cwd,
273→      ghToken: params.ghToken,
274→      claudeEnvVars: params.claudeEnvVars,
275→    });
276→    return {
277→      id: params.id,
278→      type: "workspace_init_output",
279→      agentType: "claude",
280→      slashCommands,
281→      mcpServers,
282→      error,
283→    };
284→  }
285→
286→  async updatePermissionMode(sessionId: string, permissionMode: string): Promise<void> {
287→    console.log(`Handling permission mode update for session ${sessionId}: ${permissionMode}`);
288→    const session = getSession(sessionId);
289→    const existingQuery = getQuery(sessionId);
290→
291→    if (!session) {
292→      console.log(`No active session found for ${sessionId}, ignoring permission mode update`);
293→      return;
294→    }
295→
296→    if (existingQuery) {
297→      try {
298→        await existingQuery.setPermissionMode(permissionMode as PermissionMode);
299→        console.log(`Permission mode updated to ${permissionMode} for session ${sessionId}`);
300→      } catch (error) {
301→        console.error(
302→          `Failed to update permission mode: ${getErrorMessage(error)}`
303→        );
304→      }
305→    }
306→  }
307→
308→  async getContextUsage(request: ContextUsageRequest) {
309→    const { id: sessionId, options } = request;
310→    const claudeSessionId = options.claudeSessionId;
311→
312→    console.log(
313→      `[getContextUsage] Getting context usage for session: ${sessionId}, claudeSessionId: ${claudeSessionId}`
314→    );
315→
316→    if (!claudeSessionId) throw new Error("No claudeSessionId provided");
317→    if (blockIfNotInitialized(sessionId)) throw new Error("Initialization failure");
318→
319→    const sdkOptions = {
320→      cwd: options.cwd,
321→      pathToClaudeCodeExecutable: getClaudeExecutablePath(),
322→      systemPrompt: DEFAULT_PROMPT,
323→      settingSources: DEFAULT_SETTING_SOURCES,
324→      resume: claudeSessionId,
325→    };
326→
327→    const contextUsageQuery = claudeSDK({ prompt: "/context", options: sdkOptions });
328→
329→    try {
330→      for await (const message of contextUsageQuery) {
331→        if (message.type !== "user") continue;
332→        return {
333→          type: "context_usage",
334→          id: sessionId,
335→          agentType: "claude",
336→          contextUsageData: message,
337→        };
338→      }
339→    } finally {
340→      try {
341→        await contextUsageQuery.interrupt();
342→      } catch (error) {
343→        console.error(`[getContextUsage] Error during interrupt:`, error);
344→      }
345→    }
346→
347→    throw new Error("No user message found in context usage response");
348→  }
349→
350→  // ==========================================================================
351→  // Private methods
352→  // ==========================================================================
353→
354→  private async getClaudeAccountInfo(cwd: string) {
355→    const emptyPromptInput = (async function* () {})();
356→    const sdkOptions = {
357→      cwd,
358→      pathToClaudeCodeExecutable: getClaudeExecutablePath(),
359→      systemPrompt: DEFAULT_PROMPT,
360→    };
361→    const queryResult = claudeSDK({
362→      prompt: emptyPromptInput,
363→      options: sdkOptions,
364→    });
365→    try {
366→      const accountInfo = await queryResult.accountInfo();
367→      return { accountInfo };
368→    } catch (error) {
369→      return { error: getErrorMessage(error) };
370→    } finally {
371→      void queryResult.interrupt().catch((error: Error) => {
372→        console.error(`[getClaudeAccountInfo] Error during interrupt:`, error);
373→      });
374→    }
375→  }
376→
377→  private async getClaudeWorkspaceInitData(options: WorkspaceInitOptions) {
378→    const envForClaude = buildAgentEnvironment({
379→      claudeEnvVars: options.claudeEnvVars,
380→      ghToken: options.ghToken,
381→    });
382→
383→    const emptyPromptInput = (async function* () {})();
384→    const sdkOptions = {
385→      cwd: options.cwd,
386→      pathToClaudeCodeExecutable: getClaudeExecutablePath(),
387→      systemPrompt: DEFAULT_PROMPT,
388→      settingSources: DEFAULT_SETTING_SOURCES,
389→      env: envForClaude,
390→    };
391→
392→    const queryResult = claudeSDK({ prompt: emptyPromptInput, options: sdkOptions });
393→    try {
394→      const [slashCommands, mcpServers] = await Promise.all([
395→        queryResult.supportedCommands(),
396→        queryResult.mcpServerStatus(),
397→      ]);
398→
399→      return { slashCommands, mcpServers };
400→    } catch (error) {
401→      return { error: getErrorMessage(error) };
402→    } finally {
403→      void queryResult.interrupt().catch((error: Error) => {
404→        console.error(`[getClaudeWorkspaceInitData] Error during interrupt:`, error);
405→      });
406→    }
407→  }
408→
409→  /**
410→   * Creates an async-generator-backed Claude SDK session.
411→   * Uses a message queue for multi-turn conversations.
412→   */
413→  private async processWithGenerator(
414→    sessionId: string,
415→    initialPrompt: string,
416→    options: QueryOptions
417→  ): Promise<void> {
418→    const tProcessStart = Date.now();
419→    const generatorId = `${sessionId}/${tProcessStart}`;
420→    const session = getSession(sessionId);
421→    if (!session) {
422→      console.error(`[${generatorId}] Session ${sessionId} not found`);
423→      return;
424→    }
425→    console.log(`[TIMING][${generatorId}] processWithGenerator START`);
426→
427→    // --- Message queue for multi-turn conversations ---
428→    const promptQueue = new AsyncQueue<string>([initialPrompt]);
429→
430→    session.sendMessage = (message: string) => {
431→      console.log(`[${generatorId}] Pushing message to queue`);
432→      promptQueue.push(message);
433→    };
434→
435→    session.sendTerminate = () => {
436→      console.log(`[${generatorId}] Sending terminate signal`);
437→      promptQueue.close();
438→    };
439→
440→    // Mutable context accumulated during the streaming loop.
441→    const ctx = createStreamContext();
442→
443→    try {
444→      // Build environment using shared env-builder
445→      const tEnvStart = Date.now();
446→      const envForClaude = buildAgentEnvironment({
447→        claudeEnvVars: options?.claudeEnvVars,
448→        opendevsEnv: options?.opendevsEnv,
449→        ghToken: options?.ghToken,
450→        extraEnv: { CLAUDE_CODE_ENABLE_TASKS: "true" },
451→      });
452→      console.log(
453→        `[TIMING][${generatorId}] buildAgentEnvironment took ${Date.now() - tEnvStart}ms`
454→      );
455→
456→      // Auto-inject resume for session continuity after sidecar restart.
457→      // If no explicit resume was provided and a previous agent_session_id
458→      // exists in the DB, inject it so the SDK resumes the conversation
459→      // with full context (message history, tool state).
460→      // Skip when shouldResetGenerator is true — the user explicitly wants a clean start.
461→      const tResumeStart = Date.now();
462→      if (!options.resume && !options.shouldResetGenerator) {
463→        const savedAgentSessionId = lookupAgentSessionId(sessionId);
464→        if (savedAgentSessionId) {
465→          console.log(
466→            `[${generatorId}] Auto-resuming session with agent_session_id ${savedAgentSessionId}`
467→          );
468→          options = { ...options, resume: savedAgentSessionId };
469→        }
470→      }
471→      console.log(
472→        `[TIMING][${generatorId}] resumeLookup took ${Date.now() - tResumeStart}ms resume=${!!options.resume} resumeId=${options.resume ?? "none"}`
473→      );
474→      if (options.resume) {
475→        console.log(
476→          `[RESUME-DEBUG][${generatorId}] Attempting resume with agent_session_id=${options.resume} for session=${sessionId}`
477→        );
478→      }
479→
480→      // Build SDK options using the dedicated builder
481→      const tSdkOptsStart = Date.now();
482→      const sdkOptions = buildSdkOptions(sessionId, envForClaude, options);
483→      console.log(`[TIMING][${generatorId}] buildSdkOptions took ${Date.now() - tSdkOptsStart}ms`);
484→
485→      const promptInput = buildPromptIterable(promptQueue, sessionId);
486→
487→      // Start the SDK query
488→      console.log(
489→        `[TIMING][${generatorId}] SDK spawn starting (elapsed since processStart: ${Date.now() - tProcessStart}ms)`
490→      );
491→      console.log(
492→        `[RESUME-DEBUG][${generatorId}] SDK options: resume=${sdkOptions.resume ?? "none"} cwd=${sdkOptions.cwd} model=${sdkOptions.model} permissionMode=${sdkOptions.permissionMode}`
493→      );
494→      const tSdkSpawn = Date.now();
495→      const queryResult = claudeSDK({ prompt: promptInput, options: sdkOptions });
496→      console.log(
497→        `[TIMING][${generatorId}] claudeSDK() constructor returned in ${Date.now() - tSdkSpawn}ms`
498→      );
499→
500→      setQuery(sessionId, queryResult);
501→      session.generator = queryResult[Symbol.asyncIterator]();
502→
503→      // Per-message options (constant for the lifetime of this generator)
504→      const msgOpts: ProcessMessageOptions = {
505→        sessionId,
506→        generatorId,
507→        model: options.model || "opus",
508→        isResume: !!options.resume,
509→      };
510→
511→      // Stream messages back to the frontend and persist to DB.
512→      // IMPORTANT: Persist to DB BEFORE notifying frontend, so messages
513→      // are in the DB when the frontend receives the event and fetches them.
514→      const tStreamStart = Date.now();
515→      for await (const message of queryResult) {
516→        ctx.messageCount++;
517→        if (ctx.firstMessageTime === null) {
518→          ctx.firstMessageTime = Date.now();
519→          console.log(
520→            `[TIMING][${generatorId}] FIRST_MESSAGE received after ${ctx.firstMessageTime - tSdkSpawn}ms (type=${(message as any)?.type})`
521→          );
522→        }
523→        // Deserialize, persist, and forward to frontend.
524→        // See message-processor.ts for the critical side-effect ordering.
525→        if (message) {
526→          const cleanMessage = deserializeMessage(message, generatorId);
527→          if (!cleanMessage) continue;
528→
529→          processMessage(cleanMessage, ctx, session, msgOpts);
530→
531→          // Log per-message timing for first 5 messages, then every 10th
532→          if (ctx.messageCount <= 5 || ctx.messageCount % 10 === 0) {
533→            console.log(
534→              `[TIMING][${generatorId}] msg#${ctx.messageCount} type=${cleanMessage.type}${cleanMessage.type === "result" ? "/" + cleanMessage.subtype : ""} elapsed=${Date.now() - tStreamStart}ms`
535→            );
536→          }
537→        }
538→      }
539→
540→      console.log(
541→        `[TIMING][${generatorId}] STREAM_COMPLETE messages=${ctx.messageCount} totalStreamTime=${Date.now() - tStreamStart}ms totalProcessTime=${Date.now() - tProcessStart}ms`
542→      );
543→
544→      // Post-loop: stream ended cleanly (prompt queue closed or SDK finished).
545→      // Turn-level idle is already set by processMessage on result/success.
546→      // This handles conversation-end: cancel persistence only.
547→      if (session.cancelledByUser) {
548→        persistCancellation(sessionId, "claude", options.model || "opus");
549→        console.log(`[${generatorId}] Session cancelled by user: ${sessionId}`);
550→        return;
551→      }
552→      console.log(`[${generatorId}] Stream completed: ${sessionId}`);
553→    } catch (error) {
554→      // Cancel takes priority — abort signal can surface as a thrown error.
555→      if (session.cancelledByUser) {
556→        persistCancellation(sessionId, "claude", options.model || "opus");
557→        console.log(`[${generatorId}] Session cancelled by user (catch): ${sessionId}`);
558→        return;
559→      }
560→
561→      // Post-success process exit: the CLI shuts down between turns and the
562→      // SDK reports the signal-based exit as an error. Expected cleanup, not failure.
563→      if (ctx.querySucceeded) {
564→        console.log(`[${generatorId}] Process exited after successful query (expected cleanup)`);
565→        return;
566→      }
567→
568→      // Genuine error — check if this generator still owns the session.
569→      // A rapid re-query can replace the session before the catch runs.
570→      const currentSession = getSession(sessionId);
571→      const ownsSession = !currentSession || currentSession === session;
572→
573→      const classified = classifyError(error);
574→      const errorName = error instanceof Error ? error.name : "non-Error";
575→      const errorStack = error instanceof Error
576→        ? error.stack?.split("\n").slice(0, 5).join("\n")
577→        : "no stack";
578→      const extraProps = error instanceof Error
579→        ? Object.getOwnPropertyNames(error)
580→            .filter((k) => !["message", "stack", "name"].includes(k))
581→            .map((k) => `${k}=${JSON.stringify((error as any)[k])}`)
582→            .join(" ")
583→        : "";
584→
585→      console.error(`[${generatorId}] Error in Claude query [${classified.category}]:`, classified.message);
586→      console.error(
587→        `[${generatorId}] Error details:`,
588→        `name=${errorName}`,
589→        `wasResume=${!!options.resume}`,
590→        `resumeId=${options.resume ?? "none"}`,
591→        `querySucceeded=${ctx.querySucceeded}`,
592→        `messageCount=${ctx.messageCount}`,
593→        extraProps ? `extraProps={${extraProps}}` : "extraProps={}",
594→      );
595→      console.error(`[${generatorId}] Stack (top 5):\n${errorStack}`);
596→
597→      if (ownsSession) {
598→        notifyAndRecordError(sessionId, "claude", classified, (c) => {
599→          if (c.category !== "process_exit") return c.message;
600→          const parts: string[] = [c.message];
601→          if (options.resume) parts.push("(resumed session)");
602→          if (ctx.messageCount > 0) {
603→            parts.push(`after ${ctx.messageCount} message${ctx.messageCount !== 1 ? "s" : ""}`);
604→          } else {
605→            parts.push("before receiving any messages");
606→          }
607→          if (ctx.lastResultError) parts.push(`— ${ctx.lastResultError}`);
608→          if (extraProps) parts.push(`[${extraProps}]`);
609→          return parts.join(" ");
610→        });
611→      }
612→    } finally {
613→      // Only clean up if this generator still owns the session.
614→      // A rapid re-query can replace the session before this finally runs;
615→      // blindly deleting would wipe the new session's state.
616→      const currentSession = getSession(sessionId);
617→      if (!currentSession || currentSession === session) {
618→        deleteQuery(sessionId);
619→        deleteSession(sessionId);
620→      }
621→    }
622→  }
623→}
