122→
123→// ============================================================================
124→// CodexAgentHandler
125→// ============================================================================
126→
127→export class CodexAgentHandler implements AgentHandler {
128→  readonly agentType = "codex" as const;
129→
130→  initialize(): { success: boolean; error?: string } {
131→    return initializeCodex();
132→  }
133→
134→  async handleQuery(sessionId: string, prompt: string, options: QueryOptions): Promise<void> {
135→    console.log("Handling Codex query request for session:", sessionId);
136→    if (blockIfNotInitialized(sessionId)) return;
137→
138→    const existingSession = getCodexSession(sessionId);
139→
140→    // If a query is already running, we can't send a new one (Codex exec is not multi-turn streaming)
141→    if (existingSession?.isRunning) {
142→      console.log(`Codex session ${sessionId} already running, aborting previous run`);
143→      abortCodexSession(sessionId);
144→    }
145→
146→    void this.processQuery(sessionId, prompt, options, existingSession?.threadId);
147→  }
148→
149→  async handleCancel(sessionId: string): Promise<void> {
150→    console.log("Handling Codex cancel request for session:", sessionId);
151→    if (blockIfNotInitialized(sessionId)) return;
152→
153→    // Signal abort — processQuery's post-loop/catch path owns the
154→    // status transition via persistCancellation (sets idle + notifies frontend).
155→    abortCodexSession(sessionId);
156→  }
157→
158→  handleReset(sessionId: string): void {
159→    console.log(`Handling reset generator request for Codex session: ${sessionId}`);
160→    abortCodexSession(sessionId);
161→    deleteCodexSession(sessionId);
162→  }
163→
164→  // ==========================================================================
165→  // Private methods
166→  // ==========================================================================
167→
168→  private async processQuery(
169→    sessionId: string,
170→    prompt: string,
171→    options: QueryOptions,
172→    existingThreadId?: string
173→  ): Promise<void> {
174→    const queryId = `${sessionId}/${Date.now()}`;
175→    const abortController = new AbortController();
176→
177→    const session: CodexSessionState = {
178→      threadId: existingThreadId,
179→      abortController,
180→      currentModel: options.model,
181→      cwd: options.cwd,
182→      isRunning: true,
183→    };
184→    setCodexSession(sessionId, session);
185→
186→    try {
187→      // Build environment (reuse shared env builder)
188→      const env = buildAgentEnvironment({
189→        claudeEnvVars: options?.claudeEnvVars,
190→        opendevsEnv: options?.opendevsEnv,
191→        ghToken: options?.ghToken,
192→      });
193→
194→      // Extract API key from environment
195→      const apiKey = env.OPENAI_API_KEY || env.CODEX_API_KEY;
196→      if (!apiKey) {
197→        throw new Error(
198→          "OPENAI_API_KEY or CODEX_API_KEY not found in environment. " +
199→            "Set it in Settings → Environment Variables."
200→        );
201→      }
202→
203→      const model = resolveCodexModel(options?.model);
204→      const codexPath = getCodexExecutablePath();
205→
206→      // Dynamic import — @openai/codex-sdk is ESM-only, can't be require()'d from CJS
207→      const { Codex } = await import("@openai/codex-sdk");
208→
209→      // Inject workspace context via config.developer_instructions
210→      // so it lands in the system prompt, not the user message.
211→      const workspaceContext = buildWorkspaceContext(options?.cwd);
212→      const codex = new Codex({
213→        apiKey,
214→        codexPathOverride: codexPath || undefined,
215→        env,
216→        ...(workspaceContext ? { config: { developer_instructions: workspaceContext } } : {}),
217→      });
218→
219→      // Configure thread options
220→      const threadOptions: ThreadOptions = {
221→        model,
222→        workingDirectory: options?.cwd,
223→        sandboxMode: "workspace-write",
224→        approvalPolicy: "never",
225→        skipGitRepoCheck: true,
226→        additionalDirectories: options?.additionalDirectories,
227→      };
228→
229→      // Start or resume thread
230→      const thread = existingThreadId
231→        ? codex.resumeThread(existingThreadId, threadOptions)
232→        : codex.startThread(threadOptions);
233→
234→      // Run streamed
235→      const { events } = await thread.runStreamed(prompt, {
236→        signal: abortController.signal,
237→      });
238→
239→
240→      for await (const event of events) {
241→        if (abortController.signal.aborted) break;
242→
243→        match(event)
244→          .with({ type: "thread.started" }, (e) => {
245→            session.threadId = e.thread_id;
246→            console.log(`[${queryId}] Thread started: ${e.thread_id}`);
247→          })
248→          .with({ type: P.union("item.started", "item.updated", "item.completed") }, (e) => {
249→            const blocks = mapItemToContentBlocks(e.item);
250→            if (blocks.length === 0) return;
251→
252→            // Send real-time update to frontend (every event, not just completed)
253→            FrontendClient.sendMessage({
254→              id: sessionId,
255→              type: "message",
256→              agentType: "codex",
257→              data: {
258→                type: "assistant" as const,
259→                message: {
260→                  id: `codex-${e.item.id}-${e.type}`,
261→                  role: "assistant" as const,
262→                  content: blocks,
263→                },
264→              },
265→            });
266→
267→            // Persist completed items to database
268→            if (e.type === "item.completed") {
269→              const writeResult = saveAssistantMessage(
270→                sessionId,
271→                {
272→                  id: `codex-${e.item.id}`,
273→                  role: "assistant",
274→                  content: blocks,
275→                },
276→                model
277→              );
278→              if (!writeResult.ok) {
279→                console.error(
280→                  `[${queryId}] DB write failed for assistant message: ${writeResult.error}`
281→                );
282→              }
283→            }
284→          })
285→          .with({ type: "turn.completed" }, (e) => {
286→            console.log(
287→              `[${queryId}] Turn completed. Tokens: in=${e.usage.input_tokens}, out=${e.usage.output_tokens}`
288→            );
289→
290→            FrontendClient.sendMessage({
291→              id: sessionId,
292→              type: "message",
293→              agentType: "codex",
294→              data: {
295→                type: "result",
296→                subtype: "success",
297→                usage: e.usage,
298→              },
299→            });
300→
301→            updateSessionStatus(sessionId, "idle");
302→          })
303→          .with({ type: "turn.failed" }, (e) => {
304→            const classified = classifyError(e.error);
305→            console.error(`[${queryId}] Turn failed [${classified.category}]:`, classified.message);
306→            notifyAndRecordError(sessionId, "codex", classified);
307→          })
308→          .with({ type: "error" }, (e) => {
309→            const classified = classifyError(e);
310→            console.error(
311→              `[${queryId}] Stream error [${classified.category}]:`,
312→              classified.message
313→            );
314→            notifyAndRecordError(sessionId, "codex", classified);
315→          })
316→          .with({ type: "turn.started" }, () => {
317→            // Informational — no action needed
318→          })
319→          .otherwise((e) => {
320→            // External SDK types can gain new variants — gracefully skip unknown events
321→            console.warn(`[codex] Unknown ThreadEvent type: ${(e as any).type}`);
322→          });
323→      }
324→
325→      // Only update status if this processQuery still owns the session —
326→      // a rapid re-query can replace the session before we reach this point.
327→      const currentSession = getCodexSession(sessionId);
328→      if (currentSession === session) {
329→        if (abortController.signal.aborted) {
330→          // Abort break path: record cancellation + notify frontend + set idle
331→          persistCancellation(sessionId, "codex", resolveCodexModel(options?.model));
332→        } else if (currentSession.isRunning) {
333→          // Normal completion if turn.completed wasn't received
334→          updateSessionStatus(sessionId, "idle");
335→        }
336→      }
337→
338→      console.log(`[${queryId}] Codex session completed: ${sessionId}`);
339→    } catch (error) {
340→      const raw = classifyError(error);
341→      // Also treat abortController.signal.aborted as abort (codex-specific:
342→      // the error itself might not say "abort" but the signal was triggered)
343→      const classified =
344→        raw.category !== "abort" && abortController.signal.aborted
345→          ? { ...raw, category: "abort" as const }
346→          : raw;
347→      console.error(
348→        `[${queryId}] Error in Codex query [${classified.category}]:`,
349→        classified.message
350→      );
351→
352→      // Only update status if this processQuery still owns the session.
353→      const ownsSession = getCodexSession(sessionId) === session;
354→      const isAbort = classified.category === "abort";
355→
356→      if (ownsSession) {
357→        if (isAbort) {
358→          persistCancellation(sessionId, "codex", resolveCodexModel(options?.model));
359→        } else {
360→          notifyAndRecordError(sessionId, "codex", classified);
361→        }
362→      }
363→    } finally {
364→      // Only clean up if this processQuery still owns the session.
365→      // A rapid re-query can replace the session before this finally runs;
366→      // blindly mutating would corrupt the new session's state.
367→      const currentSession = getCodexSession(sessionId);
368→      if (currentSession === session) {
369→        currentSession.isRunning = false;
370→      }
371→    }
372→  }
373→}
