  1→// sidecar/index.ts
  2→// Entry point for the OpenDevs sidecar v2 process.
  3→// Creates a Unix domain socket server that the OpenDevs frontend connects to
  4→// via newline-delimited JSON-RPC 2.0.
  5→
  6→import * as Sentry from "@sentry/node";
  7→
  8→// Initialize Sentry before anything else.
  9→// DSN passed as env var from Rust process manager (not hardcoded — open source repo).
 10→if (process.env.SENTRY_DSN) {
 11→  Sentry.init({
 12→    dsn: process.env.SENTRY_DSN,
 13→    environment: process.env.NODE_ENV === "production" ? "production" : "development",
 14→    sendDefaultPii: true,
 15→    initialScope: { tags: { process: "sidecar" } },
 16→  });
 17→}
 18→
 19→import * as net from "net";
 20→import * as fs from "fs";
 21→import * as path from "path";
 22→import * as os from "os";
 23→import * as util from "util";
 24→import { exec } from "child_process";
 25→import { StringDecoder } from "string_decoder";
 26→
 27→import { getErrorMessage } from "../shared/lib/errors";
 28→import { RpcConnection } from "./rpc-connection";
 29→import { FrontendClient } from "./frontend-client";
 30→import { closeDatabase } from "./db/index";
 31→import { reconcileStuckSessions, saveUserMessage, updateSessionStatus } from "./db/session-writer";
 32→import { classifyError } from "./agents/error-classifier";
 33→import { registerAgent, getAgent, initializeAllAgents } from "./agents/agent-handler";
 34→import { ClaudeAgentHandler } from "./agents/claude/claude-handler";
 35→import { CodexAgentHandler } from "./agents/codex/codex-handler";
 36→
 37→// ============================================================================
 38→// Logging
 39→// ============================================================================
 40→
 41→export const logFilePath = `/tmp/opendevs-${process.pid}.log`;
 42→const originalLog = console.log;
 43→
 44→const LOG_LEVEL = (process.env.LOG_LEVEL || "info") as "debug" | "info" | "error";
 45→const LOG_LEVELS = { debug: 0, info: 1, error: 2 };
 46→
 47→function shouldLog(level: "debug" | "info" | "error"): boolean {
 48→  return LOG_LEVELS[level] >= LOG_LEVELS[LOG_LEVEL];
 49→}
 50→
 51→function formatLogArgs(args: any[]): string {
 52→  return args
 53→    .map((arg) => {
 54→      if (typeof arg === "string") return arg;
 55→      if (arg instanceof Error) return `${arg.message}\n${arg.stack || ""}`;
 56→      return util.inspect(arg, { depth: 4, breakLength: Infinity });
 57→    })
 58→    .join(" ");
 59→}
 60→
 61→// Buffered log writer -- avoids synchronous appendFileSync on every log call
 62→let logBuffer = "";
 63→let flushTimer: NodeJS.Timeout | null = null;
 64→
 65→function flushLogs(): void {
 66→  if (logBuffer) {
 67→    fs.appendFileSync(logFilePath, logBuffer);
 68→    logBuffer = "";
 69→  }
 70→  flushTimer = null;
 71→}
 72→
 73→function writeLog(line: string): void {
 74→  logBuffer += line;
 75→  if (!flushTimer) {
 76→    flushTimer = setTimeout(flushLogs, 100);
 77→  }
 78→  if (logBuffer.length > 8192) {
 79→    flushLogs();
 80→  }
 81→}
 82→
 83→// Ensure logs are flushed on shutdown
 84→process.on("exit", flushLogs);
 85→
 86→console.log = (...args: any[]) => {
 87→  if (!shouldLog("info")) return;
 88→  const timestamp = new Date().toISOString();
 89→  writeLog(`[${timestamp}] ${formatLogArgs(args)}\n`);
 90→};
 91→
 92→console.error = (...args: any[]) => {
 93→  const timestamp = new Date().toISOString();
 94→  writeLog(`[${timestamp}] ERROR: ${formatLogArgs(args)}\n`);
 95→};
 96→
 97→console.debug = (...args: any[]) => {
 98→  if (!shouldLog("debug")) return;
 99→  const timestamp = new Date().toISOString();
100→  writeLog(`[${timestamp}] DEBUG: ${formatLogArgs(args)}\n`);
101→};
102→
103→// ============================================================================
104→// UnifiedSidecar
105→// ============================================================================
106→
107→class UnifiedSidecar {
108→  private socketPath: string;
109→  private server: net.Server;
110→
111→  constructor() {
112→    console.log("UnifiedSidecar: Initializing...");
113→
114→    this.socketPath = path.join(os.tmpdir(), `opendevs-sidecar-${process.pid}.sock`);
115→
116→    this.server = net.createServer((socket) => {
117→      console.log("Server: New connection accepted");
118→      this.handleConnection(socket);
119→    });
120→
121→    // Graceful shutdown handlers
122→    const gracefulShutdown = async (signal: string) => {
123→      console.log(`\n[SIGNAL] Received ${signal}, shutting down gracefully...`);
124→      try {
125→        await this.cleanup();
126→        console.log("[SIGNAL] Cleanup complete, exiting process");
127→      } catch (error) {
128→        console.error("[SIGNAL] Cleanup failed:", error);
129→      } finally {
130→        process.exit(0);
131→      }
132→    };
133→    process.on("SIGINT", () => gracefulShutdown("SIGINT"));
134→    process.on("SIGTERM", () => gracefulShutdown("SIGTERM"));
135→  }
136→
137→  /**
138→   * Wires up all JSON-RPC methods and notifications on a new connection.
139→   */
140→  private setupJsonRpc(rpcTunnel: RpcConnection, socket: net.Socket): void {
141→    FrontendClient.attachTunnel(rpcTunnel);
142→
143→    // --- Query (dispatch to agent by agentType) ---
144→    // Returns synchronous ACK/reject before async streaming begins.
145→    // handleQuery is NOT awaited — the ACK returns immediately after validation.
146→    FrontendClient.onQuery(rpcTunnel, async (request) => {
147→      const tQueryReceived = Date.now();
148→      console.log(`[TIMING][QUERY] RECEIVED session=${request.id} agent=${request.agentType} promptLength=${request.prompt?.length ?? 0}`);
149→      const agent = getAgent(request.agentType);
150→      if (!agent) {
151→        return { accepted: false, reason: `No agent registered for type: ${request.agentType}` };
152→      }
153→
154→      // Atomically persist user message + set status='working' before dispatching agent.
155→      // If the DB write fails, nothing is persisted and the frontend gets a clean rejection.
156→      const writeResult = saveUserMessage(
157→        request.id,
158→        request.prompt,
159→        request.options.model || "opus"
160→      );
161→      if (!writeResult.ok) {
162→        // Emit queryError notification so callers that sent a JSON-RPC notification
163→        // (no id → return value is silently dropped) still receive the error.
164→        FrontendClient.sendError({
165→          id: request.id,
166→          type: "error",
167→          error: writeResult.error,
168→          agentType: request.agentType,
169→          category: "internal",
170→        });
171→        return { accepted: false, reason: `Failed to save message: ${writeResult.error}` };
172→      }
173→
174→      agent.handleQuery(request.id, request.prompt, request.options).catch((err) => {
175→        console.error(`[QUERY] Unhandled error in ${request.agentType} handleQuery:`, err);
176→        // Recover: update session status so it doesn't stay stuck in "working".
177→        // processWithGenerator has its own try/catch that handles most errors,
178→        // but if handleQuery itself rejects (before or outside the generator),
179→        // this is the last line of defense.
180→        const classified = classifyError(err);
181→        FrontendClient.sendError({
182→          id: request.id,
183→          type: "error",
184→          error: classified.message,
185→          agentType: request.agentType,
186→          category: classified.category,
187→        });
188→        updateSessionStatus(request.id, "error", classified.message, classified.category);
189→      });
190→      console.log(`[TIMING][QUERY] DISPATCHED session=${request.id} dispatchTime=${Date.now() - tQueryReceived}ms`);
191→      return { accepted: true };
192→    });
193→
194→    // --- Cancel (dispatch to agent by agentType) ---
195→    FrontendClient.onCancel(rpcTunnel, (request) => {
196→      const agent = getAgent(request.agentType);
197→      if (agent) void agent.handleCancel(request.id);
198→    });
199→
200→    // --- Auth check (Claude-specific RPC) ---
201→    FrontendClient.onClaudeAuth(rpcTunnel, (request) => {
202→      const claude = getAgent("claude") as ClaudeAgentHandler;
203→      return claude.claudeAuth({ id: request.id, cwd: request.options.cwd });
204→    });
205→
206→    // --- Workspace init (Claude-specific RPC) ---
207→    FrontendClient.onWorkspaceInit(rpcTunnel, (request) => {
208→      const claude = getAgent("claude") as ClaudeAgentHandler;
209→      return claude.workspaceInit({
210→        id: request.id,
211→        cwd: request.options.cwd,
212→        ghToken: request.options.ghToken,
213→        claudeEnvVars: request.options.claudeEnvVars,
214→      });
215→    });
216→
217→    // --- Context usage (Claude-specific RPC) ---
218→    FrontendClient.onContextUsage(rpcTunnel, (request) => {
219→      const claude = getAgent("claude") as ClaudeAgentHandler;
220→      return claude.getContextUsage(request);
221→    });
222→
223→    // --- Permission mode updates (Claude-specific) ---
224→    FrontendClient.onUpdatePermissionMode(rpcTunnel, (request) => {
225→      const claude = getAgent("claude") as ClaudeAgentHandler;
226→      if (claude) void claude.updatePermissionMode(request.id, request.permissionMode);
227→    });
228→
229→    // --- Reset generator (dispatch to agent by agentType) ---
230→    FrontendClient.onResetGenerator(rpcTunnel, (request) => {
231→      const agent = getAgent(request.agentType);
232→      if (agent) agent.handleReset(request.id);
233→    });
234→
235→    // Note: socket "close" handler is in handleConnection() which also calls
236→    // rpcTunnel.stop() and FrontendClient.detachTunnel(). No need for a
237→    // duplicate handler here.
238→  }
239→
240→  /**
241→   * Handles a new TCP/Unix socket connection.
242→   * Sets up line-based JSON-RPC message framing.
243→   */
244→  private handleConnection(socket: net.Socket): void {
245→    console.log("Client connected");
246→    const rpcTunnel = new RpcConnection(socket);
247→    this.setupJsonRpc(rpcTunnel, socket);
248→
249→    let buffer = "";
250→    const decoder = new StringDecoder("utf8");
251→
252→    socket.on("data", (data) => {
253→      buffer += decoder.write(data);
254→      console.debug("Received data with length", data.length);
255→
256→      const lines = buffer.split("\n");
257→      buffer = lines.pop() || "";
258→
259→      for (const line of lines) {
260→        if (line.trim()) {
261→          rpcTunnel.handleLine(line);
262→        }
263→      }
264→    });
265→
266→    socket.on("error", (error: any) => {
267→      console.error("Socket error:", error);
268→    });
269→
270→    socket.on("close", (hadError) => {
271→      console.log(`Client disconnected, hadError: ${hadError}`);
272→      rpcTunnel.stop();
273→      FrontendClient.detachTunnel(rpcTunnel);
274→    });
275→  }
276→
277→  /**
278→   * Kills any remaining Claude child processes spawned by this sidecar.
279→   */
280→  private async killRemainingChildProcesses(): Promise<void> {
281→    return new Promise((resolve) => {
282→      const command = `/usr/bin/pgrep -P ${process.pid}`;
283→      exec(command, (error, stdout) => {
284→        if (error) {
285→          console.log("[CLEANUP] No child processes found");
286→          resolve();
287→          return;
288→        }
289→        const childPids = stdout
290→          .trim()
291→          .split("\n")
292→          .filter((pid) => pid);
293→        if (childPids.length === 0) {
294→          console.log("[CLEANUP] No child processes to kill");
295→          resolve();
296→          return;
297→        }
298→        console.log(`[CLEANUP] Found ${childPids.length} child processes: ${childPids.join(", ")}`);
299→        childPids.forEach((pid) => {
300→          try {
301→            process.kill(Number(pid), "SIGTERM");
302→            console.log(`[CLEANUP] Sent SIGTERM to child PID ${pid}`);
303→          } catch (e) {
304→            const errorMsg = getErrorMessage(e);
305→            console.log(`[CLEANUP] Failed to kill child PID ${pid}: ${errorMsg}`);
306→          }
307→        });
308→        resolve();
309→      });
310→    });
311→  }
312→
313→  private async cleanup(): Promise<void> {
314→    await this.killRemainingChildProcesses();
315→    try {
316→      closeDatabase();
317→    } catch (err) {
318→      console.error("[CLEANUP] Failed to close database:", err);
319→    }
320→    if (fs.existsSync(this.socketPath)) {
321→      fs.unlinkSync(this.socketPath);
322→      console.log("[CLEANUP] Removed socket file");
323→    }
324→    this.server.close();
325→  }
326→
327→  /**
328→   * Starts the sidecar:
329→   * 1. Clean up stale socket
330→   * 2. Initialize the Claude handler (verify executable)
331→   * 3. Listen on Unix domain socket
332→   * 4. Print SOCKET_PATH=<path> to stdout (consumed by the OpenDevs app)
333→   */
334→  async start(): Promise<void> {
335→    await this.cleanup();
336→
337→    // Register all agent handlers
338→    registerAgent(new ClaudeAgentHandler());
339→    registerAgent(new CodexAgentHandler());
340→
341→    // Initialize all registered agents
342→    console.log("Initializing agent handlers...");
343→    const initResults = initializeAllAgents();
344→    for (const [agentType, result] of initResults) {
345→      if (!result.success) {
346→        console.error(`${agentType} initialization failed:`, result.error);
347→      } else {
348→        console.log(`${agentType} handler initialized successfully`);
349→      }
350→    }
351→
352→    // Reset sessions stuck in "working" status from a previous sidecar lifecycle.
353→    // Must run after DB is initialized (getDatabase auto-inits) but before
354→    // accepting connections, so no race with incoming queries.
355→    const reconcileResult = reconcileStuckSessions();
356→    if (!reconcileResult.ok) {
357→      console.error(`Failed to reconcile stuck sessions: ${reconcileResult.error}`);
358→    }
359→
360→    return new Promise((resolve, reject) => {
361→      this.server.listen(this.socketPath, () => {
362→        console.log(`Unified sidecar listening on ${this.socketPath}`);
363→        console.log(`Sidecar PID: ${process.pid}`);
364→
365→        // Print the socket path to stdout so the OpenDevs app can connect
366→        originalLog(`SOCKET_PATH=${this.socketPath}`);
367→        resolve();
368→      });
369→
370→      this.server.on("error", (error: any) => {
371→        console.error("Server error:", error);
372→        reject(error);
373→      });
374→    });
375→  }
376→}
377→
378→// ============================================================================
379→// Global error handlers
380→// ============================================================================
381→
382→process.on("uncaughtException", (error: any) => {
383→  console.error("Uncaught Exception:", error.message);
384→  if (error.stack) console.error("Stack:", error.stack);
385→  Sentry.captureException(error);
386→  Sentry.close(2000).finally(() => process.exit(1));
387→});
388→
389→process.on("unhandledRejection", (reason, _promise) => {
390→  // Sentry's built-in onUnhandledRejectionIntegration captures and normalizes
391→  // rejection reasons automatically. We only log here for local visibility.
392→  if (reason instanceof Error) {
393→    console.error("Unhandled Rejection:", reason.message);
394→    if (reason.stack) console.error("Stack:", reason.stack);
395→  }
396→  console.error("Unhandled Rejection Reason:", JSON.stringify(reason, null, 2));
397→});
398→
399→// ============================================================================
400→// Bootstrap
401→// ============================================================================
402→
403→const sidecar = new UnifiedSidecar();
404→sidecar.start().catch((error) => {
405→  console.error("Startup failed:", error);
406→  process.exit(1);
407→});
408→

