  1→export type RuntimeAgentType = "claude" | "codex" | "unknown";
  2→
  3→export type ThinkingLevel = "NONE" | "LOW" | "MEDIUM" | "HIGH";
  4→
  5→/**
  6→ * Agent type lock constraint:
  7→ * Once a session has messages (message_count > 0), its agent harness
  8→ * (claude or codex) is fixed for the session's lifetime. The sidecar
  9→ * binds to a specific SDK on first query and cannot switch mid-session.
 10→ *
 11→ * - Within the same harness: model switching is allowed (e.g. Sonnet → Opus)
 12→ * - Across harnesses: requires opening a new chat tab (new session)
 13→ *
 14→ * The UI enforces this by disabling cross-group items in the model picker
 15→ * when hasMessages is true. See MessageInput's model picker dropdown.
 16→ */
 17→
 18→// ── Agent Model Option ───────────────────────────────────────────────
 19→
 20→interface AgentModelOption {
 21→  /** Model identifier sent to the sidecar */
 22→  model: string;
 23→  /** Human-readable label */
 24→  label: string;
 25→  /** Show "New" badge in picker */
 26→  isNew?: boolean;
 27→}
 28→
 29→// ── Agent Config ─────────────────────────────────────────────────────
 30→
 31→/**
 32→ * Per-agent configuration record.
